import React from 'react';
import ProductCard from './ProductCard';

const products = [
  { id: 1, name: 'Dell XPS 13 9315 (Sky Blue)', image: 'https://via.placeholder.com/300', specs: ['Core i5', '16GB', '512GB SSD'], price: '24.990.000₫', oldPrice: '28.500.000₫', badge: '-12%' },
  { id: 2, name: 'MacBook Air M2 13-inch 2023', image: 'https://via.placeholder.com/300', specs: ['M2 8-core', '8GB', '256GB SSD'], price: '26.490.000₫' },
  { id: 3, name: 'Asus ROG Zephyrus G14 2024', image: 'https://via.placeholder.com/300', specs: ['R9-7940HS', '16GB', 'RTX 4060'], price: '38.990.000₫' },
  { id: 4, name: 'Lenovo ThinkPad X1 Carbon Gen 11', image: 'https://via.placeholder.com/300', specs: ['Core i7', '32GB', '1TB SSD'], price: '42.500.000₫' },
  { id: 5, name: 'Microsoft Surface Pro 9 Platinum', image: 'https://via.placeholder.com/300', specs: ['Core i5', '16GB', '256GB SSD'], price: '22.800.000₫' },
  { id: 6, name: 'HP Spectre x360 14 (2023) Black', image: 'https://via.placeholder.com/300', specs: ['Core i7', '16GB', '512GB SSD'], price: '31.200.000₫' },
  { id: 7, name: 'Acer Swift Edge 16 OLED', image: 'https://via.placeholder.com/300', specs: ['Ryzen 7', '16GB', 'OLED 4K'], price: '27.500.000₫' },
  { id: 8, name: 'MSI Stealth 14 Studio Blue', image: 'https://via.placeholder.com/300', specs: ['Core i7', 'RTX 4050', '16GB'], price: '34.990.000₫', badge: 'New' }
];

const ProductGrid = () => {
  return (
    <section className="flex-1">
      <div className="flex flex-col sm:flex-row sm:items-center justify-between gap-4 mb-6 bg-white dark:bg-background-dark p-4 rounded-xl border border-slate-200 dark:border-slate-800 shadow-sm">
        <p className="text-sm"><span className="font-bold text-primary">24</span> sản phẩm được tìm thấy</p>
        <div className="flex items-center gap-2 overflow-x-auto">
          <span className="text-sm text-slate-500 whitespace-nowrap">Sắp xếp:</span>
          {['Mới nhất', 'Bán chạy', 'Giá thấp - cao', 'Giá cao - thấp'].map((sort, idx) => (
            <button key={sort} className={`px-3 py-1.5 text-xs ${idx === 0 ? 'bg-primary text-white' : 'bg-slate-100 dark:bg-slate-800'} rounded-lg whitespace-nowrap`}>
              {sort}
            </button>
          ))}
        </div>
      </div>
      <div className="grid grid-cols-1 sm:grid-cols-2 xl:grid-cols-4 gap-4">
        {products.map(product => (
          <ProductCard key={product.id} product={product} />
        ))}
      </div>
      <div className="flex justify-center mt-12 mb-8 gap-2">
        <button className="w-10 h-10 flex items-center justify-center rounded-lg border border-slate-200 hover:border-primary hover:text-primary transition-all">
          <span className="material-symbols-outlined">chevron_left</span>
        </button>
        <button className="w-10 h-10 flex items-center justify-center rounded-lg bg-primary text-white font-bold">1</button>
        <button className="w-10 h-10 flex items-center justify-center rounded-lg border border-slate-200 hover:border-primary hover:text-primary transition-all">2</button>
        <button className="w-10 h-10 flex items-center justify-center rounded-lg border border-slate-200 hover:border-primary hover:text-primary transition-all">3</button>
        <button className="w-10 h-10 flex items-center justify-center rounded-lg border border-slate-200 hover:border-primary hover:text-primary transition-all">
          <span className="material-symbols-outlined">chevron_right</span>
        </button>
      </div>
    </section>
  );
};

export default ProductGrid;
